	m
}

ASSIGNED {
	v		(mV)
	dt		(ms)
	ica		(mA/cm2)
	m_inf
	tadj
	gcaLlva		(mho/cm2)
}

BREAKPOINT {
	SOLVE states METHOD cnexp
	gcaLlva = gcaLlvabar * m
	ica = gcaLlvabar * m * (v - eca)
}

DERIVATIVE states {
	evaluate_fct(v)
	m' = (m_inf - m) / tau_m :'
}

