FUNCTION alphaKx(v(mV)) (/ms)
{ 
	alphaKx = 0.001*aoKx * exp( (v - VhalfKx)/(2*SKx) )
}

FUNCTION betaKx(v(mV))  (/ms)
{ 
	betaKx = 0.001*aoKx*exp( - ( v-VhalfKx)/(2*SKx) )
}


PROCEDURE rate(v (mV))
{
        LOCAL aKx, bKx

	aKx = alphaKx(v)
	bKx = betaKx(v)
	tauKx = 1/(aKx + bKx)
	infKx = aKx*tauKx
	
}

