PROCEDURE trates(vm) {  
        LOCAL  a, b

	a = trap0(vm,-29,0.5,0.18)
	b = 6*exp(-(vm+45)/15)
	minf = a/(a+b)
	mtau = 1/(a+b)

	a = 0.15*exp(-(vm+47)/20)
	b = 2.8/(1+exp(-0.1*(vm+20)))
	hinf = a/(a+b)
	htau =  1/(a+b)
}

FUNCTION trap0(v,th,a,q) {
	if (fabs(v-th) > 1e-6) {
	        trap0 = a * (v - th) / (1 - exp(-(v - th)*q))
	} else {
	        trap0 = a / q
 	}
}

