        cainit = 0.000184 (mM)
        celsius = 35  (degC)
        gkbar = 800e-6 (S/cm2)
        ek = -100 (mV)


}

ASSIGNED { 
           ik		(mA/cm2)
           oinf           
}


BREAKPOINT {
