NEURON { 
	SUFFIX dcnh
	NONSPECIFIC_CURRENT ih
	RANGE gbar, ih, eh, m
	GLOBAL qdeltat
} 
 
UNITS { 
	(mA) = (milliamp) 
	(mV) = (millivolt) 
} 
 
