	v (mV)
	ih (mA/cm2) 
	eh (mV)
	minf
	taum (ms)
} 
 
STATE {
	m
} 

INITIAL { 
    rate(v) 
	taum = 400 / qdeltat
    m = minf 
} 
 
BREAKPOINT { 
    SOLVE states METHOD cnexp 
	ih = gbar * m * m * (v - eh)
} 
 
DERIVATIVE states { 
	rate(v) 
	m' = (minf - m) / taum 
} 

