NEURON {
	POINT_PROCESS gapvdep
	NONSPECIFIC_CURRENT i
	RANGE gg,i,slow
	POINTER vpregap
}
PARAMETER {
	v (millivolt)
	vpregap (millivolt)
	gg = 5e-4 (micromho)
}

STATE { slow
}
ASSIGNED {
	i (nanoamp)
}
