	SOLVE sssss METHOD cnexp
	i = (v - vpregap)*gg*(vdepfac(v-slow))
VERBATIM

ENDVERBATIM
}

DERIVATIVE sssss {
	slow' = (vpregap-slow)/tau_slow(vpregap)
}




FUNCTION vdepfac(v){
vdepfac = 1.0/(1+exp(-(0.12*(v-5))))

}

FUNCTION tau_slow(ww){
tau_slow=0.2+200/(1+exp(-0.5*(ww+50)))
}

